// ImageUploadInput.tsx - drag-and-drop + paste support
import { useState, useCallback, useRef } from "react";

interface Attachment { file: File; preview: string; }

export function ImageUploadInput({
  onSend,
}: {
  onSend: (text: string, attachment: File | null) => void;
}) {
  const [draft, setDraft] = useState("");
  const [attachment, setAttachment] = useState<Attachment | null>(null);
  const [dragging, setDragging] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const attach = useCallback((file: File) => {
    if (!file.type.startsWith("image/")) return;
    const preview = URL.createObjectURL(file);
    setAttachment({ file, preview });
  }, []);

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setDragging(false);
    const file = e.dataTransfer.files[0];
    if (file) attach(file);
  };

  const onPaste = (e: React.ClipboardEvent) => {
    const item = Array.from(e.clipboardData.items).find(i => i.type.startsWith("image/"));
    if (item) attach(item.getAsFile()!);
  };

  const send = () => {
    onSend(draft, attachment?.file ?? null);
    setDraft("");
    setAttachment(null);
  };

  return (
    <div
      className={`border rounded-xl p-2 transition-colors ${
        dragging ? "border-indigo-500 bg-indigo-950/30" : "border-slate-700 bg-slate-800"
      }`}
      onDragOver={e => { e.preventDefault(); setDragging(true); }}
      onDragLeave={() => setDragging(false)}
      onDrop={onDrop}
    >
      {attachment && (
        <div className="relative inline-block mb-2">
          <img src={attachment.preview} alt="attachment"
               className="max-h-32 rounded-lg object-cover border border-slate-600" />
          <button
            onClick={() => setAttachment(null)}
            className="absolute -top-1 -right-1 bg-red-600 text-white rounded-full w-5 h-5 text-xs flex items-center justify-center"
          >x</button>
        </div>
      )}
      <div className="flex gap-2 items-end">
        <textarea
          ref={inputRef}
          value={draft}
          onChange={e => setDraft(e.target.value)}
          onPaste={onPaste}
          onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); send(); }}}
          className="flex-1 bg-transparent text-slate-100 text-sm resize-none outline-none min-h-[40px]"
          placeholder={dragging ? "Drop image here..." : "Type a message or paste an image..."}
          rows={2}
        />
        <input ref={inputRef} type="file" accept="image/*" className="hidden"
               onChange={e => e.target.files?.[0] && attach(e.target.files[0])} />
        <button onClick={() => inputRef.current?.click()}
                className="text-slate-400 hover:text-slate-200 text-xl px-1">+</button>
        <button onClick={send} className="bg-indigo-600 text-white px-3 py-1 rounded-lg text-sm">Send</button>
      </div>
    </div>
  );
}

// VoiceInput.tsx - browser MediaRecorder -> Whisper -> chat
import { useState, useRef } from "react";

export function VoiceInput({ onTranscript }: { onTranscript: (text: string) => void }) {
  const [recording, setRecording] = useState(false);
  const mediaRef  = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const start = async () => {
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const mr = new MediaRecorder(stream, { mimeType: "audio/webm" });
    chunksRef.current = [];
    mr.ondataavailable = e => chunksRef.current.push(e.data);
    mr.onstop = async () => {
      const blob = new Blob(chunksRef.current, { type: "audio/webm" });
      const form = new FormData();
      form.append("audio", blob, "voice.webm");
      const res = await fetch(`/chat/${sessionId}/voice-message`, { method: "POST", body: form });
      const { transcript } = await res.json();
      onTranscript(transcript);
    };
    mr.start();
    mediaRef.current = mr;
    setRecording(true);
  };

  const stop = () => {
    mediaRef.current?.stop();
    mediaRef.current?.stream.getTracks().forEach(t => t.stop());
    setRecording(false);
  };

  return (
    <button
      onMouseDown={start}
      onMouseUp={stop}
      onTouchStart={start}
      onTouchEnd={stop}
      className={`rounded-full p-2 transition-colors ${
        recording ? "bg-red-600 animate-pulse" : "bg-slate-700 hover:bg-slate-600"
      }`}
      title={recording ? "Release to send" : "Hold to record"}
    >
      {recording ? "..." : "mic"}
    </button>
  );
}

// ImageMessage.tsx - render images in the chat transcript
export function AttachmentPreview({ role, attachmentUrl }: { role: string; attachmentUrl: string }) {
  const [expanded, setExpanded] = useState(false);

  return (
    <div className={`max-w-xs ${role === "user" ? "ml-auto" : ""}`}>
      <img
        src={attachmentUrl}
        alt="attachment"
        className={`rounded-xl object-contain border border-slate-700 cursor-pointer
                    transition-all ${expanded ? "max-w-full max-h-screen" : "max-h-40 max-w-xs"}`}
        onClick={() => setExpanded(e => !e)}
      />
      {expanded && (
        <div className="text-xs text-slate-500 mt-1">Click to collapse</div>
      )}
    </div>
  );
}

